from processor import process_event
from store import clear, get_apply_log, snapshot, restore


def ingest(events, max_retries=3):
    """
    Process events one-by-one with retry logic at the API layer.
    For each event we snapshot the store state before attempting to process it.
    If processing raises, we restore the snapshot and retry up to max_retries.

    Returns per-event result dicts and the audit count.
    """
    clear()
    results = []

    for e in events:
        last_exception = None
        for attempt in range(max_retries):
            snap = snapshot()
            try:
                value = process_event(e)
                results.append({"ok": True, "value": value, "attempt": attempt})
                last_exception = None
                break
            except Exception as exc:
                # Restore any partial side effects from this failed attempt
                restore(snap)
                last_exception = exc
                # continue to retry
        else:
            # all attempts failed
            results.append({"ok": False, "value": None, "attempt": max_retries - 1})

    trail = get_apply_log()
    return {"results": results, "audit_count": len(trail)}


def ingest_with_retry(events):
    clear()
    results = []
    for e in events:
        results.append(handle_with_retry(e))
    trail = get_apply_log()
    return {"results": results, "audit_count": len(trail)}
